// descendants returns all descendant nodes in depth-first order.
pub fn (node Node) descendants() []Node {
	mut descendants := []Node{}

	for child in node.child_nodes() {
		descendants << child
		descendants << child.descendants()
	}

	return descendants
}

// find_first returns the first node with kind in depth-first order.
pub fn (node Node) find_first(kind NodeKind) ?Node {
	if node.base().kind == kind {
		return node
	}

	for child in node.child_nodes() {
		if found := child.find_first(kind) {
			return found
		}
	}

	return none
}

// find_all returns all nodes with kind in depth-first order.
pub fn (node Node) find_all(kind NodeKind) []Node {
	mut matches := []Node{}
	node.collect_kind(kind, mut matches)
	return matches
}

// walk visits this node and every allowed descendant.
pub fn (node &Node) walk(mut visitor Visitor) ! {
	visitor.visit(node)!
	for child in node.child_nodes() {
		child.walk(mut visitor)!
	}
}

// collect_kind appends nodes matching kind.
fn (node Node) collect_kind(kind NodeKind, mut matches []Node) {
	if node.base().kind == kind {
		matches << node
	}
	for child in node.child_nodes() {
		child.collect_kind(kind, mut matches)
	}
}

